// src/lib/trace.ts
type TraceLevel = "log" | "warn" | "error";

type TraceEntry = {
  ts: number;
  iso: string;
  level: TraceLevel;
  tag: string;
  msg: string;
  data?: unknown;
  stack?: string;
};

const MAX = 500;
type TraceWindow = Window & { __CGPTBE_TRACE__?: TraceEntry[] };

// Глобальный буфер в окне страницы (удобно копировать из DevTools)
function getBuf(): TraceEntry[] {
  const w = window as TraceWindow;
  if (!w.__CGPTBE_TRACE__) w.__CGPTBE_TRACE__ = [];
  return w.__CGPTBE_TRACE__ as TraceEntry[];
}

// Быстрый флаг включения: localStorage["cgptbe.trace"]="1"
export function isTraceEnabled(): boolean {
  try {
    return localStorage.getItem("cgptbe.trace") === "1";
  } catch {
    return false;
  }
}

export function trace(tag: string, msg: string, data?: unknown, level: TraceLevel = "log") {
  if (!isTraceEnabled()) return;

  const ts = Date.now();
  const entry: TraceEntry = {
    ts,
    iso: new Date(ts).toISOString(),
    level,
    tag,
    msg,
    data
  };

  // stack (обрезаем шум trace() и js runtime)
  try {
    const stack = new Error().stack;
    if (stack) entry.stack = stack.split("\n").slice(2, 10).join("\n");
  } catch {}

  const buf = getBuf();
  buf.push(entry);
  if (buf.length > MAX) buf.splice(0, buf.length - MAX);

  const prefix = `[cgptbe][${entry.iso}][${entry.tag}]`;
  if (level === "warn") console.warn(prefix, msg, data ?? "");
  else if (level === "error") console.error(prefix, msg, data ?? "");
  else console.log(prefix, msg, data ?? "");
}

// Утилита: быстро выгрузить всё в консоли
export function dumpTrace(): TraceEntry[] {
  return getBuf().slice();
}

export type TraceLogger = {
  log: (msg: string, data?: unknown) => void;
  info: (msg: string, data?: unknown) => void;
  warn: (msg: string, data?: unknown) => void;
  error: (msg: string, data?: unknown) => void;
};

/**
 * Small helper to create a scoped logger.
 *
 * Usage:
 *   const trace = createTrace("entry:content");
 *   trace.error("Something failed", err);
 */
export function createTrace(tag: string): TraceLogger {
  return {
    log: (msg, data) => trace(tag, msg, data, "log"),
    info: (msg, data) => trace(tag, msg, data, "log"),
    warn: (msg, data) => trace(tag, msg, data, "warn"),
    error: (msg, data) => trace(tag, msg, data, "error")
  };
}
