import { SETTINGS_DEFAULTS, Settings } from "../domain/settings";

export function norm(value: string | null) {
  return String(value || "").toLowerCase();
}

export function isVisible(el: Element | null) {
  if (!el) return false;
  const r = el.getBoundingClientRect();
  return r.width > 0 && r.height > 0;
}

export function isElementVisible(el: Element | null) {
  if (!el || el.nodeType !== 1) return false;
  const r = el.getBoundingClientRect();
  if (r.width <= 1 || r.height <= 1) return false;
  const cs = getComputedStyle(el);
  if (cs.display === "none") return false;
  if (cs.visibility === "hidden") return false;
  if (cs.opacity === "0") return false;
  return true;
}

export function isDisabled(el: HTMLElement | null) {
  if (!el) return true;
  if (el instanceof HTMLButtonElement && el.disabled) return true;
  if (el.hasAttribute("disabled")) return true;
  const ariaDisabled = el.getAttribute("aria-disabled");
  if (ariaDisabled && ariaDisabled !== "false") return true;
  return false;
}

export function normalizeSettings(data: Record<string, unknown>): Settings {
  const base = SETTINGS_DEFAULTS;

  const obj = data && typeof data === "object" ? (data as Record<string, unknown>) : {};

  const legacySkipKey = typeof obj.skipKey === "string" ? (obj.skipKey as string) : null;

  const legacyHoldToSend = typeof obj.holdToSend === "boolean" ? (obj.holdToSend as boolean) : null;
  void legacyHoldToSend;

  // legacy-правило autoSend (как у тебя было)
  const autoSend =
    typeof obj.autoSend === "boolean"
      ? (obj.autoSend as boolean)
      : legacySkipKey === "None"
        ? false
        : true;

  const readBool = (key: keyof Settings): boolean => {
    const v = obj[key as string];
    return typeof v === "boolean" ? v : (base[key] as boolean);
  };

  const readNumber = (key: keyof Settings): number => {
    const v = obj[key as string];
    return typeof v === "number" && Number.isFinite(v) ? v : (base[key] as number);
  };

  const wideChatWidth = (() => {
    const n = readNumber("wideChatWidth");
    return Math.min(100, Math.max(0, n));
  })();

  return {
    ...base,

    // special-case legacy
    autoSend,

    // bools (всё без копипасты)
    allowAutoSendInCodex: readBool("allowAutoSendInCodex"),
    editLastMessageOnArrowUp: readBool("editLastMessageOnArrowUp"),
    autoExpandChats: readBool("autoExpandChats"),
    autoTempChat: readBool("autoTempChat"),
    tempChatEnabled: readBool("tempChatEnabled"),
    oneClickDelete: readBool("oneClickDelete"),
    startDictation: readBool("startDictation"),
    ctrlEnterSends: readBool("ctrlEnterSends"),
    showCompatibilityWarnings: readBool("showCompatibilityWarnings"),

    // numbers
    wideChatWidth
  };
}

export function isThenable<T>(value: void | Promise<T>): value is Promise<T> {
  return Boolean(value) && typeof (value as Promise<T>).then === "function";
}
