import { startContentScript } from "../application/contentScript";
import { StorageApi, createStoragePort } from "../infra/storageAdapter";
import { ensureWebExtPolyfill } from "../lib/webextPolyfill";
import { createTrace } from "../lib/trace";

const trace = createTrace("entry:content");

type WebExtGlobal = typeof globalThis & {
  browser?: {
    storage?: unknown;
    runtime?: { lastError?: unknown };
  };
  chrome?: {
    storage?: unknown;
    runtime?: { lastError?: unknown };
  };
};

(async () => {
  try {
    ensureWebExtPolyfill();

    const g = globalThis as WebExtGlobal;

    // Storage is the only API we really need here.
    const storageApi = (g.browser?.storage ?? g.chrome?.storage) as unknown as
      | StorageApi
      | undefined;

    if (!storageApi) {
      trace.error("No storage API available (browser.storage / chrome.storage missing)");
      return;
    }

    const lastError = () => g.chrome?.runtime?.lastError ?? g.browser?.runtime?.lastError ?? null;
    const storagePort = createStoragePort({ storageApi, lastError });

    await Promise.resolve(startContentScript({ storagePort }));
  } catch (e: unknown) {
    trace.error("Content script entry failed", e);
  }
})();
